int font_init(font *f) {
    f->glyph_w = 6;
    f->glyph_h = 8;
    int cols = 16;
    int rows = 6;
    f->atlas_w = cols * f->glyph_w;
    f->atlas_h = rows * f->glyph_h;

    unsigned char *pix = calloc(f->atlas_w * f->atlas_h * 4, 1);
    if (!pix) return 0;

    for (int g = 0; g < 95; g++) {
        int gx = g % cols;
        int gy = g / cols;
        for (int yy = 0; yy < 8; yy++) {
            unsigned char row = font_6x8[g][yy];
            for (int xx = 0; xx < 6; xx++) {
                int px = gx * 6 + xx;
                int py = gy * 8 + yy;
                int idx = (py * f->atlas_w + px) * 4;
                unsigned bit = (row >> (7 - xx)) & 1;
                pix[idx + 0] = bit ? 255 : 0;
                pix[idx + 1] = bit ? 255 : 0;
                pix[idx + 2] = bit ? 255 : 0;
                pix[idx + 3] = bit ? 255 : 0;
            }
        }
    }

    glGenTextures(1, &f->tex);
    glBindTexture(GL_TEXTURE_2D, f->tex);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_NEAREST);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_NEAREST);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S,     GL_CLAMP_TO_EDGE);
    glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T,     GL_CLAMP_TO_EDGE);
    glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, f->atlas_w, f->atlas_h, 0,
                 GL_RGBA, GL_UNSIGNED_BYTE, pix);
    free(pix);
    LOGI("font atlas %dx%d", f->atlas_w, f->atlas_h);
    return 1;
}

void font_destroy(font *f) {
    if (f->tex) glDeleteTextures(1, &f->tex);
    f->tex = 0;
}

void font_measure(const font *f, const char *s, int *out_w, int *out_h) {
    int lw = 0, w = 0, h = f->glyph_h;
    for (const char *p = s; *p; p++) {
        if (*p == '\n') { if (lw > w) w = lw; lw = 0; h += f->glyph_h; continue; }
        lw += f->glyph_w;
    }
    if (lw > w) w = lw;
    if (out_w) *out_w = w;
    if (out_h) *out_h = h;
}

int font_build_text(const font *f, const char *s, int x, int y,
                    float *out_verts, int max_verts) {
    int written = 0;
    int cx = x, cy = y;
    int cols = 16;

    for (const char *p = s; *p; p++) {
        if (*p == '\n') { cx = x; cy += f->glyph_h; continue; }
        int g = (int)(*p) - 32;
        if (g < 0 || g >= 95) g = (int)'?' - 32;

        int gx = g % cols;
        int gy = g / cols;
        float u0 = (float)(gx * f->glyph_w) / (float)f->atlas_w;
        float v0 = (float)(gy * f->glyph_h) / (float)f->atlas_h;
        float u1 = (float)((gx + 1) * f->glyph_w) / (float)f->atlas_w;
        float v1 = (float)((gy + 1) * f->glyph_h) / (float)f->atlas_h;

        float x0 = (float)cx, y0 = (float)cy;
        float x1 = x0 + f->glyph_w;
        float y1 = y0 + f->glyph_h;

        if (written + 24 > max_verts) break;
        float *o = out_verts + written;
        o[0]  = x0; o[1]  = y0; o[2]  = u0; o[3]  = v0;
        o[4]  = x1; o[5]  = y0; o[6]  = u1; o[7]  = v0;
        o[8]  = x1; o[9]  = y1; o[10] = u1; o[11] = v1;
        o[12] = x0; o[13] = y0; o[14] = u0; o[15] = v0;
        o[16] = x1; o[17] = y1; o[18] = u1; o[19] = v1;
        o[20] = x0; o[21] = y1; o[22] = u0; o[23] = v1;
        written += 24;

        cx += f->glyph_w;
    }
    return written;
}
